"use client";
import { useFieldArray, useForm } from "react-hook-form"
import CategoryForm from "../ui/form/categoryForm"
import type { Category, MenuForm } from "@/data/types/dishMenu"
import { useRouter } from "next/navigation";
import { Button } from "@radix-ui/themes"

import { useParams } from "next/navigation"

import { doc, getDoc } from "firebase/firestore";
import { db } from "@/lib/firebase/client";
import { getAuth } from "firebase/auth";

type newCategory = {
    name: string,
    categorys: Category[]
}

const MenuForm = async () => {
    const form = useForm<MenuForm>({
        mode: "onSubmit",
        defaultValues: {
            categories: [{
                name: "",
                id: ""
            },
            ]
        }

    })
    const { handleSubmit } = form
    const auth = getAuth()
    const uid = auth.currentUser?.uid
    if (!uid) return;
    const userSnap = await getDoc(doc(db, "users", uid));
    const firmId = userSnap.data()?.firmId;
    const router = useRouter()
    const params = useParams<{ firmId: string, id: string }>()
    const { fields, append, remove } = useFieldArray({
        name: "categories",
        control: form.control
    })

    const onAddNewCategory = () => {
        const category: Category = {
            name: "",
            id: crypto.randomUUID(),
            dishes: [],
        }
        append(category)
    }

    const onHandleSubmit = async (data: MenuForm) => {
        try {
            const restaurantId = params.id
            const firmId = params.firmId
            const menuRef = doc(
                db,
                "firms",
                firmId,
                "restaurants",
                restaurantId,
                "menu", "main")
        }
        catch (error) {
            console.log("error:", error)
        }
    }

    return (
        <form onSubmit={form.handleSubmit(onHandleSubmit)}>
            <div className="p-2" >
                <div >{fields.map((category, indexCategory) =>
                    <div key={category.id} >
                        <CategoryForm
                            form={form}
                            index={indexCategory}
                            category={category as Category}
                            onRemoveCategory={() => remove(indexCategory)}

                        />
                    </div>
                )}
                </div>
                <div className=" flex gap-2 p-2"><Button
                    onClick={() => { }}
                    className="mt-6 bg-green-600 text-white"
                >
                    Zapisz menu
                </Button>
                    <Button
                        onSubmit={handleSubmit(onHandleSubmit)}
                        onClick={() => router.push(`/restaurant/${params.id}`)}
                    >
                        Powrót do restauracji
                    </Button>
                    <Button
                        color="blue"
                        onClick={() => onAddNewCategory()}
                    >
                        Dodaj kategorie
                    </Button></div>
            </div >
        </form>)
}
export default MenuForm